diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 756b25ac9856..dab34c1fb921 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -20983,6 +20983,26 @@ bool SLPVectorizerPass::vectorizeGEPIndices(BasicBlock *BB, BoUpSLP &R) {
       if (Candidates.size() < 2)
         continue;

+      // Skip vectorization if GEP indices come from multiple basic blocks to avoid
+      // assertion failures in getLastInstructionInBundle.
+      BasicBlock *CommonBB = nullptr;
+      bool HasMultipleBBs = false;
+      for (auto *V : Candidates) {
+        auto *GEP = cast<GetElementPtrInst>(V);
+        auto *GEPIdx = GEP->idx_begin()->get();
+        if (auto *IdxInst = dyn_cast<Instruction>(GEPIdx)) {
+          if (!CommonBB) {
+            CommonBB = IdxInst->getParent();
+          } else if (IdxInst->getParent() != CommonBB) {
+            HasMultipleBBs = true;
+            break;
+          }
+        }
+      }
+      if (HasMultipleBBs) {
+        continue;
+      }
+
       // Add the single, non-constant index of each candidate to the bundle. We
       // ensured the indices met these constraints when we originally collected
       // the getelementptrs.

